// Objects with named fields; the chart maps them to x/y via the parsing option.
const productsList = [
  {
    productId: 1,
    productName: 'Cold Brew',
    unitPrice: 24.5,
    unitsInStock: 320,
  },
  {
    productId: 2,
    productName: 'Espresso Beans',
    unitPrice: 18.0,
    unitsInStock: 210,
  },
  {
    productId: 3,
    productName: 'Matcha Powder',
    unitPrice: 32.0,
    unitsInStock: 140,
  },
  {
    productId: 4,
    productName: 'Chai Blend',
    unitPrice: 15.5,
    unitsInStock: 410,
  },
  {
    productId: 5,
    productName: 'Hazelnut Syrup',
    unitPrice: 12.0,
    unitsInStock: 275,
  },
]

var options = {
  series: [
    {
      name: 'Price',
      data: productsList,
      parsing: {
        x: 'productName',
        y: 'unitPrice',
      },
    },
    {
      name: 'Stock',
      data: productsList,
      parsing: {
        x: 'productName',
        y: 'unitsInStock',
      },
    },
  ],
  chart: {
    type: 'bar',
    height: 350,
  },
  title: {
    text: 'Product Price & Stock',
    align: 'left',
  },
  subtitle: {
    text: 'Object arrays mapped to x/y via the parsing option',
    align: 'left',
  },
  plotOptions: {
    bar: {
      horizontal: false,
      borderRadius: 0,
    },
  },
  dataLabels: {
    enabled: false,
  },
  stroke: {
    show: true,
    width: 2,
  },
  fill: {
    opacity: 1,
  },
  yaxis: [
    {
      seriesName: 'Price',
      min: 0,
      title: {
        text: 'Price',
      },
      labels: {
        formatter: (val) => {
          return '$' + val.toFixed(2)
        },
      },
    },
    {
      opposite: true,
      seriesName: 'Stock',
      min: 0,
      title: {
        text: 'Stock',
      },
      labels: {
        formatter: (val) => {
          return val
        },
      },
    },
  ],
}

var chart = new ApexCharts(document.querySelector('#chart'), options)
chart.render()
